// Implicit Intent: describes an ACTION, not a specific class
val intent = Intent(Intent.ACTION_VIEW).apply {
    data = Uri.parse("https://weathernow.example.com/forecast/today")
}
startActivity(intent)

val intent = Intent(Intent.ACTION_VIEW).apply {
    data = Uri.parse("somecustomscheme://rareaction")
}
startActivity(intent)

// No installed app declares an intent-filter matching this scheme

val intent = Intent(this, ForecastDetailActivity::class.java).apply {
    putExtra("city_name", "Seattle")
    putExtra("forecast_day", "Monday")
}
startActivity(intent)

// Starting an Activity (covered throughout this chapter)
startActivity(Intent(this, ForecastDetailActivity::class.java))

// Starting a Service — same Intent mechanism, different
// kind of component, no visible screen involved
startService(Intent(this, WeatherSyncService::class.java))
